function drawWrap() {
  const c = document.createElement("canvas");
  c.width = 512;
  c.height = 1024;
  const ctx = c.getContext("2d");
  ctx.clearRect(0, 0, 512, 1024);
  drawBrushX(ctx, 256, 210, 200, "rgba(201,164,92,0.9)", "rgba(138,111,60,0.9)");
  ctx.save();
  ctx.translate(256, 600);
  ctx.rotate(-Math.PI / 2);
  ctx.fillStyle = P.goldBright;
  ctx.font = "800 92px Helvetica, Arial, sans-serif";
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.fillText("CACTUS X", 0, 0);
  ctx.restore();
  drawCactus(ctx, 256, 990, 130, "rgba(201,164,92,0.8)");
  const t = new THREE.CanvasTexture(c);
  t.anisotropy = 4;
  return t;
}

