function labelSprite(text) {
  const c = document.createElement("canvas");
  c.width = 256;
  c.height = 80;
  const ctx = c.getContext("2d");
  ctx.fillStyle = "rgba(20,20,22,0.85)";
  rr(ctx, 48, 12, 160, 56, 12);
  ctx.fill();
  ctx.strokeStyle = "#4a90d9";
  ctx.lineWidth = 2;
  ctx.stroke();
  ctx.fillStyle = "#cfe3fa";
  ctx.font = "500 30px Helvetica, Arial, sans-serif";
  ctx.textAlign = "center";
  ctx.fillText(text, 128, 50);
  const tex = new THREE.CanvasTexture(c);
  const mat = new THREE.SpriteMaterial({ map: tex, transparent: true, depthTest: false });
  const s = new THREE.Sprite(mat);
  s.scale.set(0.6, 0.19, 1);
  return s;
}

function dimLine(a, b, offsetDir, offsetAmt, text) {
  const g = new THREE.Group();
  const off = offsetDir.clone().multiplyScalar(offsetAmt);
  const p1 = a.clone().add(off);
  const p2 = b.clone().add(off);
  const mat = new THREE.LineBasicMaterial({ color: 0x4a90d9 });
  const mk = (pts) => new THREE.Line(new THREE.BufferGeometry().setFromPoints(pts), mat);
  g.add(mk([p1, p2]));
  g.add(mk([a, p1]));
  g.add(mk([b, p2]));
  const lbl = labelSprite(text);
  lbl.position.copy(p1.clone().add(p2).multiplyScalar(0.5)).add(offsetDir.clone().multiplyScalar(0.09));
  g.add(lbl);
  return g;
}

export default function CactusXMachine() {
  const mountRef = useRef(null);
  const S = useRef({}).current;
  const [autoRotate, setAutoRotate] = useState(true);
  const [explode, setExplode] = useState(false);
  const [showDims, setShowDims] = useState(false);
  const [ledsOn, setLedsOn] = useState(true);
  const [line1, setLine1] = useState(P.line1);
  const [line2, setLine2] = useState(P.line2);
  const [bannerColor, setBannerColor] = useState(P.banner);

  useEffect(() => {
    const mount = mountRef.current;
    const W = mount.clientWidth;
    const H = 560;

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(40, W / H, 0.1, 100);
    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setClearColor(0x000000, 0);
    renderer.setSize(W, H);
    mount.appendChild(renderer.domElement);

    scene.add(new THREE.AmbientLight(0xffffff, 0.8));
    const key = new THREE.DirectionalLight(0xfff2dc, 1.05);
    key.position.set(3, 5, 4);
    scene.add(key);
    const fillL = new THREE.DirectionalLight(0xffffff, 0.45);
    fillL.position.set(-2, 2, 5);
    scene.add(fillL);
    const rim = new THREE.DirectionalLight(0xc9a45c, 0.5);
    rim.position.set(-4, 3, -3);
    scene.add(rim);

    const machine = new THREE.Group();
    scene.add(machine);

    const steel = (color, rough = 0.45, metal = 0.35) =>
      new THREE.MeshStandardMaterial({ color, roughness: rough, metalness: metal });

    const parts = [];
    const addPart = (group, out) => {
      group.userData.home = group.position.clone();
      group.userData.out = out;
      parts.push(group);
      machine.add(group);
    };

    const C0 = shades("#8a7350");
    const plinthMat = steel(C0.plinth, 0.4, 0.4);
    const plinth = new THREE.Group();
    plinth.add(new THREE.Mesh(new THREE.BoxGeometry(1.1, 0.1, 0.94), plinthMat));
    plinth.position.set(0, 0.05, 0);
    addPart(plinth, new THREE.Vector3(0, -0.28, 0));

    const bodyMat = steel(C0.cabinet, 0.4, 0.4);
    const doorMat = steel(C0.door, 0.4, 0.4);
    const body = new THREE.Group();
    body.add(new THREE.Mesh(new THREE.BoxGeometry(1.12, 1.86, 0.96), bodyMat));
    const door = new THREE.Mesh(new THREE.BoxGeometry(0.85, 1.84, 0.02), doorMat);
    door.position.set(-0.115, 0, 0.485);
    body.add(door);
    const wrapMat = new THREE.MeshStandardMaterial({ map: drawWrap(), transparent: true, roughness: 0.4, metalness: 0.3 });
    const backP = new THREE.Mesh(new THREE.PlaneGeometry(1.08, 1.82), wrapMat);
    backP.rotation.y = Math.PI;
    backP.position.set(0, 0, -0.483);
    body.add(backP);
    const sideTex = new THREE.TextureLoader().load(SIDE_ART);
    sideTex.anisotropy = 4;
    const sideMat = new THREE.MeshBasicMaterial({ map: sideTex });
    const sideGlossMat = new THREE.MeshBasicMaterial({ map: glossTexture(), transparent: true });
    const screenL = new THREE.Mesh(new THREE.PlaneGeometry(0.84, 1.54), sideMat);
    screenL.rotation.y = -Math.PI / 2;
    screenL.position.set(-0.5635, 0.02, 0);
    const glossL = new THREE.Mesh(new THREE.PlaneGeometry(0.84, 1.54), sideGlossMat);
    glossL.rotation.y = -Math.PI / 2;
    glossL.position.set(-0.5655, 0.02, 0);
    const screenR = new THREE.Mesh(new THREE.PlaneGeometry(0.84, 1.54), sideMat);
    screenR.rotation.y = Math.PI / 2;
    screenR.position.set(0.5635, 0.02, 0);
    const glossR = new THREE.Mesh(new THREE.PlaneGeometry(0.84, 1.54), sideGlossMat);
    glossR.rotation.y = Math.PI / 2;
    glossR.position.set(0.5655, 0.02, 0);
    body.add(screenL, glossL, screenR, glossR);
    body.position.set(0, 1.03, 0);
    addPart(body, new THREE.Vector3(0, 0, 0));

    const railMat = steel(C0.rail, 0.4, 0.4);
    const rail = new THREE.Group();
    rail.add(new THREE.Mesh(new THREE.BoxGeometry(0.24, 1.84, 0.02), railMat));
    const ledMat = new THREE.MeshStandardMaterial({ color: 0xffe9c4, emissive: 0xffdda0, emissiveIntensity: 1.3, roughness: 0.3 });
    const ledTop = new THREE.Mesh(new THREE.BoxGeometry(0.014, 0.66, 0.008), ledMat);
    ledTop.position.set(0, 0.48, 0.014);
    const ledBot = new THREE.Mesh(new THREE.BoxGeometry(0.014, 0.66, 0.008), ledMat);
    ledBot.position.set(0, -0.44, 0.014);
    rail.add(ledTop, ledBot);
    const logo = new THREE.Mesh(new THREE.PlaneGeometry(0.21, 0.082), new THREE.MeshBasicMaterial({ map: drawLogo(), transparent: true }));
    logo.position.set(0, 0.82, 0.012);
    rail.add(logo);
    rail.position.set(0.44, 1.03, 0.485);
    addPart(rail, new THREE.Vector3(0.55, 0, 0.1));

    const pay = new THREE.Group();
    pay.add(new THREE.Mesh(new THREE.BoxGeometry(0.1, 0.15, 0.045), steel(0x060606, 0.4, 0.3)));
    const payFace = new THREE.Mesh(new THREE.PlaneGeometry(0.085, 0.13), new THREE.MeshBasicMaterial({ map: drawPay() }));
    payFace.position.z = 0.0235;
    pay.add(payFace);
    pay.position.set(0.44, 1.14, 0.51);
    addPart(pay, new THREE.Vector3(0.55, 0, 0.35));

    const bezelMat = steel(C0.bezel, 0.4, 0.4);
    const screenG = new THREE.Group();
    screenG.add(new THREE.Mesh(new THREE.BoxGeometry(0.8, 1.36, 0.02), bezelMat));
    const artTex = new THREE.TextureLoader().load(FRONT_ART);
    artTex.anisotropy = 4;
    const screenMat = new THREE.MeshBasicMaterial({ map: artTex });
    const screen = new THREE.Mesh(new THREE.PlaneGeometry(0.74, 1.28), screenMat);
    screen.position.z = 0.015;
    screenG.add(screen);
    const gloss = new THREE.Mesh(
      new THREE.PlaneGeometry(0.74, 1.28),
      new THREE.MeshBasicMaterial({ map: glossTexture(), transparent: true })
    );
    gloss.position.z = 0.017;
    screenG.add(gloss);
    screenG.position.set(-0.115, 1.24, 0.495);
    addPart(screenG, new THREE.Vector3(0, 0, 0.5));

    const tray = new THREE.Group();
    tray.add(new THREE.Mesh(new THREE.BoxGeometry(0.62, 0.2, 0.06), steel(0x080604, 0.6, 0.3)));
    const trayFace = new THREE.Mesh(new THREE.PlaneGeometry(0.64, 0.21), new THREE.MeshBasicMaterial({ map: drawTray(), transparent: true }));
    trayFace.position.z = 0.032;
    tray.add(trayFace);
    tray.position.set(-0.115, 0.44, 0.48);
    addPart(tray, new THREE.Vector3(0, 0, 0.4));

    const boxMat = new THREE.MeshStandardMaterial({ color: P.can, roughness: 0.4, metalness: 0.3 });
    const bandMat = new THREE.MeshStandardMaterial({ color: 0xc9a45c, roughness: 0.25, metalness: 0.7 });
    const can = new THREE.Group();
    const canBody = new THREE.Mesh(new THREE.BoxGeometry(0.09, 0.14, 0.05), boxMat);
    const canBand = new THREE.Mesh(new THREE.BoxGeometry(0.092, 0.03, 0.052), bandMat);
    can.add(canBody, canBand);
    can.visible = false;
    machine.add(can);

    const dims = new THREE.Group();
    dims.add(
      dimLine(new THREE.Vector3(-0.56, 0, 0.48), new THREE.Vector3(-0.56, 1.96, 0.48), new THREE.Vector3(-1, 0, 0), 0.22, MM.h + " mm"),
      dimLine(new THREE.Vector3(-0.56, 0, 0.48), new THREE.Vector3(0.56, 0, 0.48), new THREE.Vector3(0, 0, 1), 0.25, MM.w + " mm"),
      dimLine(new THREE.Vector3(0.56, 0, -0.48), new THREE.Vector3(0.56, 0, 0.48), new THREE.Vector3(1, 0, 0), 0.25, MM.d + " mm")
    );
    dims.visible = false;
    scene.add(dims);

    S.dims = dims;
    S.bodyMat = bodyMat;
    S.doorMat = doorMat;
    S.railMat = railMat;
    S.plinthMat = plinthMat;
    S.bezelMat = bezelMat;
    S.ledMat = ledMat;
    S.screenMat = screenMat;
    S.sideMat = sideMat;
    S.can = can;
    S.theta = 0.6;
    S.phi = 1.25;
    S.radius = 4.4;
    S.tTheta = 0.6;
    S.tPhi = 1.25;
    S.tRadius = 4.4;
    S.explodeF = 0;
    S.target = new THREE.Vector3(0, 1.0, 0);
    S.auto = true;

    let dragging = false, px = 0, py = 0;
    const el = renderer.domElement;
    el.style.touchAction = "none";
    el.style.cursor = "grab";
    const down = (e) => {
      dragging = true;
      px = e.clientX;
      py = e.clientY;
      el.style.cursor = "grabbing";
      el.setPointerCapture(e.pointerId);
    };
    const move = (e) => {
      if (!dragging) return;
      S.tTheta -= (e.clientX - px) * 0.006;
      S.tPhi -= (e.clientY - py) * 0.005;
      S.tPhi = Math.max(0.2, Math.min(1.55, S.tPhi));
      px = e.clientX;
      py = e.clientY;
    };
    const up = () => {
      dragging = false;
      el.style.cursor = "grab";
    };
    const wheel = (e) => {
      e.preventDefault();
      S.tRadius = Math.max(2.2, Math.min(8, S.tRadius + e.deltaY * 0.0035));
    };
    el.addEventListener("pointerdown", down);
    el.addEventListener("pointermove", move);
    el.addEventListener("pointerup", up);
    el.addEventListener("pointerleave", up);
    el.addEventListener("wheel", wheel, { passive: false });

    const REST_Y = 0.55;
    let raf;
    const animate = () => {
      raf = requestAnimationFrame(animate);
      if (S.auto && !dragging) S.tTheta += 0.0035;
      S.theta += (S.tTheta - S.theta) * 0.08;
      S.phi += (S.tPhi - S.phi) * 0.08;
      S.radius += (S.tRadius - S.radius) * 0.08;
      const tf = S.explodeTarget || 0;
      S.explodeF += (tf - S.explodeF) * 0.07;
      parts.forEach((p) => {
        p.position.copy(p.userData.home.clone().add(p.userData.out.clone().multiplyScalar(S.explodeF)));
      });
      if (S.canActive) {
        S.canVy -= 0.0042;
        can.position.y += S.canVy;
        can.rotation.z += 0.05;
        if (can.position.y <= REST_Y) {
          can.position.y = REST_Y;
          if (Math.abs(S.canVy) > 0.008) {
            S.canVy = -S.canVy * 0.38;
          } else {
            S.canVy = 0;
            S.canActive = false;
            can.rotation.z = Math.round(can.rotation.z / (Math.PI * 2)) * Math.PI * 2 + 1.5708;
          }
        }
      }
      camera.position.set(
        S.target.x + S.radius * Math.sin(S.phi) * Math.sin(S.theta),
        S.target.y + S.radius * Math.cos(S.phi),
        S.target.z + S.radius * Math.sin(S.phi) * Math.cos(S.theta)
      );
      camera.lookAt(S.target);
      renderer.render(scene, camera);
    };
    animate();

    const onResize = () => {
      const w = mount.clientWidth;
      camera.aspect = w / H;
      camera.updateProjectionMatrix();
      renderer.setSize(w, H);
    };
    window.addEventListener("resize", onResize);

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener("resize", onResize);
      el.removeEventListener("pointerdown", down);
      el.removeEventListener("pointermove", move);
      el.removeEventListener("pointerup", up);
      el.removeEventListener("pointerleave", up);
      el.removeEventListener("wheel", wheel);
      renderer.dispose();
      mount.removeChild(el);
    };
  }, []);

  useEffect(() => { S.auto = autoRotate; }, [autoRotate]);
  useEffect(() => { S.explodeTarget = explode ? 1 : 0; }, [explode]);
  useEffect(() => { if (S.dims) S.dims.visible = showDims; }, [showDims]);
  useEffect(() => {
    if (S.ledMat) {
      S.ledMat.emissiveIntensity = ledsOn ? 1.3 : 0.05;
      S.ledMat.color.set(ledsOn ? 0xffe9c4 : 0x444444);
    }
  }, [ledsOn]);



  const vend = () => {
    if (S.can) {
      S.can.visible = true;
      S.can.position.set(-0.115, 2.15, 0.56);
      S.can.rotation.set(0, 0, 0);
      S.canVy = 0;
      S.canActive = true;
    }
  };

  const setView = (theta, phi, radius) => {
    S.tTheta = theta;
    S.tPhi = phi;
    S.tRadius = radius;
    setAutoRotate(false);
  };

  const btn = {
    background: "#ffffff", color: "#1f1f24", border: "1px solid #d9d9df",
    borderRadius: 8, padding: "7px 12px", fontSize: 13, cursor: "pointer",
  };
  const chip = (active) => ({
    ...btn,
    background: active ? "#8a6f3c" : "#ffffff",
    color: active ? "#ffffff" : "#1f1f24",
    borderColor: active ? "#8a6f3c" : "#d9d9df",
  });

  return (
    <div style={{ background: "transparent", minHeight: "100vh", padding: 20, fontFamily: "Helvetica, Arial, sans-serif", color: "#1f1f24", boxSizing: "border-box" }}>
      <div style={{ maxWidth: 960, margin: "0 auto" }}>
        <div style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between", flexWrap: "wrap", gap: 8 }}>
          <h1 style={{ fontSize: 20, fontWeight: 600, margin: "0 0 4px" }}>
            Cactus X connected retail machine — Sandstone
          </h1>
          <span style={{ fontSize: 12, color: "#84848c" }}>drag to orbit, scroll to zoom</span>
        </div>

        <div ref={mountRef} style={{ width: "100%", height: 560, marginTop: 12, background: "transparent" }} />

        <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginTop: 12 }}>
          <button style={{ ...btn, background: "#8a6f3c", color: "#fff", borderColor: "#8a6f3c" }} onClick={vend}>
            Vend a product
          </button>
          <button style={btn} onClick={() => setView(0, 1.35, 3.6)}>Front</button>
          <button style={btn} onClick={() => setView(0.7, 1.2, 4.2)}>Three quarter</button>
          <button style={btn} onClick={() => setView(Math.PI / 2, 1.35, 4.0)}>Side</button>
          <button style={btn} onClick={() => setView(0.6, 0.35, 4.6)}>Top</button>
          <button style={chip(autoRotate)} onClick={() => setAutoRotate(!autoRotate)}>
            {autoRotate ? "Auto rotate on" : "Auto rotate off"}
          </button>
          <button style={chip(explode)} onClick={() => setExplode(!explode)}>
            {explode ? "Assemble" : "Exploded view"}
          </button>
          <button style={chip(showDims)} onClick={() => setShowDims(!showDims)}>
            {showDims ? "Hide dimensions" : "Dimensions"}
          </button>
          <button style={chip(ledsOn)} onClick={() => setLedsOn(!ledsOn)}>
            {ledsOn ? "LEDs on" : "LEDs off"}
          </button>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: 12, marginTop: 16 }}>
          <div style={{ background: "#fafafa", border: "1px solid #e4e4e9", borderRadius: 12, padding: 14 }}>
            <div style={{ fontSize: 12, color: "#84848c", marginBottom: 8 }}>Specification</div>
            <table style={{ width: "100%", fontSize: 13, borderCollapse: "collapse" }}>
              <tbody>
                {[
                  ["Height", MM.h + " mm"],
                  ["Width", MM.w + " mm"],
                  ["Depth", MM.d + " mm"],
                  ["Display", '43" portrait touchscreen'],
                  ["Side screens", "2 \u00D7 digital ad panels"],
                  ["Payment", "Contactless + age verification"],
                  ["Lighting", "Twin LED rail"],
                ].map(([k, v]) => (
                  <tr key={k}>
                    <td style={{ color: "#84848c", padding: "4px 0" }}>{k}</td>
                    <td style={{ textAlign: "right", padding: "4px 0" }}>{v}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}
